export const PROBLEM_MAP = Object.fromEntries(
  PROBLEMS.map(p => [p.id, p])
) as Record<string, Problem>

export function problemsByPattern(patternId: string): Problem[] {
  return PROBLEMS.filter(p => p.patternId === patternId)
}

/**
 * Returns problems for a given pattern node.
 * Falls back to a BFS subtree search when the node itself has no direct problems —
 * so clicking any ancestor node still surfaces the problems of its descendants.
 */
export function problemsByPatternOrSubtree(patternId: string): Problem[] {
  // Direct match first
  const direct = PROBLEMS.filter(p => p.patternId === patternId)
  if (direct.length > 0) return direct

  // BFS through child IDs collected from the static PATTERN_MAP
  const allIds = new Set<string>([patternId])
  const queue  = [patternId]
  while (queue.length > 0) {
    const cur  = queue.shift()!
    const node = PATTERN_MAP[cur]
    if (node) {
      for (const child of node.childIds) {
        if (!allIds.has(child)) {
          allIds.add(child)
          queue.push(child)
        }
      }
    }
  }

  return PROBLEMS.filter(p => allIds.has(p.patternId))
}
